  ('social-worker-moex-08230', 'social-worker', 'social-worker-moex-098-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「30位曾為身體或情緒暴力受害者的婦女」的陳述表達了我們在設計方案撰寫目標時五個構成目標要素中的那一個？', '["時間架構", "改變的標的", "欲達成的結果", "用以記錄、監督、測量成品之判準"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "bd967293a7d9", "answer_pdf_sha1": "822b4e781d88", "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
